# CoAP Constants
COAP_VERSION = 1
COAP_TYPE_CON = 0
COAP_TYPE_NON = 1
COAP_TYPE_ACK = 2
COAP_TYPE_RST = 3

COAP_GET = 1
COAP_POST = 2
COAP_PUT = 3
COAP_DELETE = 4

COAP_RESPONSE_CONTENT = 69
COAP_RESPONSE_CHANGED = 68
COAP_RESPONSE_NOT_FOUND = 132
COAP_RESPONSE_METHOD_NOT_ALLOWED = 133

COAP_OPTION_URI_PATH = 11
COAP_OPTION_CONTENT_FORMAT = 12

COAP_PORT = 5683

class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = COAP_TYPE_CON
        self.token_length = 0
        self.code = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''
    
    @staticmethod
    def parse(data):
        msg = CoapMessage()
        if len(data) < 4:
            return None
        
        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.type = (first_byte >> 4) & 0x03
        msg.token_length = first_byte & 0x0F
        
        msg.code = data[1]
        msg.message_id = struct.unpack('!H', data[2:4])[0]
        
        offset = 4
        if msg.token_length > 0:
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length
        
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break
            
            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1
            
            if option_delta == 13:
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                option_delta = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
            
            if option_length == 13:
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                option_length = struct.unpack('!H', data[offset:offset+2])[0] + 269
                offset += 2
            
            option_value = data[offset:offset + option_length]
            offset += option_length
            
            if msg.options:
                option_number = msg.options[-1][0] + option_delta
            else:
                option_number = option_delta
            
            msg.options.append((option_number, option_value))
        
        return msg
    
    def encode(self):
        data = bytearray()
        first_byte = (self.version << 6) | (self.type << 4) | self.token_length
        data.append(first_byte)
        data.append(self.code)
        data.extend(struct.pack('!H', self.message_id))
        
        if self.token_length > 0:
            data.extend(self.token)
        
        prev_option_number = 0
        for option_number, option_value in sorted(self.options):
            delta = option_number - prev_option_number
            length = len(option_value)
            
            delta_ext = 0
            length_ext = 0
            
            if delta < 13:
                delta_nibble = delta
            elif delta < 269:
                delta_nibble = 13
                delta_ext = delta - 13
            else:
                delta_nibble = 14
                delta_ext = delta - 269
            
            if length < 13:
                length_nibble = length
            elif length < 269:
                length_nibble = 13
                length_ext = length - 13
            else:
                length_nibble = 14
                length_ext = length - 269
            
            data.append((delta_nibble << 4) | length_nibble)
            
            if delta_nibble == 13:
                data.append(delta_ext)
            elif delta_nibble == 14:
                data.extend(struct.pack('!H', delta_ext))
            
            if length_nibble == 13:
                data.append(length_ext)
            elif length_nibble == 14:
                data.extend(struct.pack('!H', length_ext))
            
            data.extend(option_value)
            prev_option_number = option_number
        
        if self.payload:
            data.append(0xFF)
            data.extend(self.payload)
        
        return bytes(data)
    
    def get_uri_path(self):
        path_segments = []
        for option_number, option_value in self.options:
            if option_number == COAP_OPTION_URI_PATH:
                path_segments.append(option_value.decode('utf-8'))
        return '/' + '/'.join(path_segments) if path_segments else '/'

class CoapServer:
    def __init__(self, port=COAP_PORT):
        self.port = port
        self.sock = None
        self.resources = {}
        self.temp_sensor = None
        self.light_state = False
        
    def add_resource(self, path, handler):
        self.resources[path] = handler
    
    def start(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', self.port))
        self.sock.setblocking(False)
        print(f"CoAP server started on port {self.port}")
    
    def handle_request(self):
        try:
            data, addr = self.sock.recvfrom(1024)
            msg = CoapMessage.parse(data)
            
            if msg is None:
                return
            
            response = CoapMessage()
            response.version = COAP_VERSION
            response.type = COAP_TYPE_ACK
            response.message_id = msg.message_id
            response.token = msg.token
            response.token_length = msg.token_length
            
            uri_path = msg.get_uri_path()
            
            if uri_path in self.resources:
                handler = self.resources[uri_path]
                
                if msg.code == COAP_GET:
                    result = handler('GET', None)
                    response.code = COAP_RESPONSE_CONTENT
                    response.payload = result.encode('utf-8')
                    response.options.append((COAP_OPTION_CONTENT_FORMAT, b'\x00'))
                
                elif msg.code == COAP_PUT:
                    payload = msg.payload.decode('utf-8') if msg.payload else ''
                    handler('PUT', payload)
                    response.code = COAP_RESPONSE_CHANGED
                    response.payload = b'Changed'
                
                else:
                    response.code = COAP_RESPONSE_METHOD_NOT_ALLOWED
                    response.payload = b'Method Not Allowed'
            else:
                response.code = COAP_RESPONSE_NOT_FOUND
                response.payload = b'Not Found'
            
            self.sock.sendto(response.encode(), addr)
            
        except OSError:
            pass
    
    def run(self):
        while True:
            self.handle_request()
            time.sleep_ms(10)

def read_temperature():
    try:
        import dht
        sensor = dht.DHT22(machine.Pin(4))
        sensor.measure()
        return sensor.temperature()
    except:
        return 20.0 + random.uniform(-5, 5)

def temp_handler(method, payload):
    if method == 'GET':
        temp = read_temperature()
        return f'{{"temperature": {temp:.2f}}}'
    return ''

def light_handler(method, payload):
    global light_state
    if method == 'GET':
        return f'{{"light": {"true" if light_state else "false"}}}'
    elif method == 'PUT':
        if payload:
            try:
                import json
                data = json.loads(payload)
                light_state = data.get('light', False)
                try:
                    led = machine.Pin(2, machine.Pin.OUT)
                    led.value(1 if light_state else 0)
                except:
                    pass
            except:
                if 'true' in payload.lower() or '1' in payload:
                    light_state = True
                else:
                    light_state = False
        return f'{{"light": {"true" if light_state else "false"}}}'
    return ''

light_state = False

server = CoapServer()
server.add_resource('/sensors/temp', temp_handler)
server.add_resource('/actuators/light', light_handler)

server.start()
server.run()